package il.co.dcd.composermapper.model; import java.nio.file.Path; import java.util.*;
public class ContextDef { private String id; private String parent; private String type; private Path sourceFile; private final Map<String,String> rawAttributes=new LinkedHashMap<>(); public String getId(){return id;} public void setId(String id){this.id=id;} public String getParent(){return parent;} public void setParent(String p){this.parent=p;} public String getType(){return type;} public void setType(String t){this.type=t;} public Path getSourceFile(){return sourceFile;} public void setSourceFile(Path p){this.sourceFile=p;} public Map<String,String> getRawAttributes(){return rawAttributes;} }
